@use '../../../styles/tokens' as *;

.list-item {
  display: flex;
  align-items: center;
  justify-content: space-between;
  height: $list-item-height;
  padding: 0 $space-2;
  border-radius: $radius-list-item;
  cursor: pointer;
  transition: background-color $transition-fast ease;

  &:hover:not(&--active) {
    background-color: $color-surface-hover;
  }

  &:focus-visible {
    outline: 2px solid $color-accent;
    outline-offset: -2px;
  }

  &--active {
    background-color: $color-selection-background;
  }
}

.list-item__left {
  display: flex;
  align-items: center;
  gap: $space-3;
  min-width: 0;
  flex: 1;
}

.list-item__icon {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 20px;
  height: 20px;
  flex-shrink: 0;
  color: $text-600;
}

.list-item__title {
  font-size: $font-base;
  color: $color-text-primary;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  min-width: 0;
}

.list-item__subtitle {
  font-size: $font-sm;
  color: $text-600;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  flex-shrink: 1;
  min-width: 0;
}

.list-item__accessories {
  display: flex;
  align-items: center;
  gap: $space-2;
  flex-shrink: 0;
  margin-left: $space-2;
}

.list-item__accessory {
  display: inline-flex;
  align-items: center;
  gap: $space-1;
}

.list-item__accessory-text {
  font-size: $font-xs;
  color: $text-400;
  white-space: nowrap;
}

