export { List } from './list';
export { useListContext } from './list_context';
export { ListItem } from './list_item/list_item';
export type { ListItemAccessory, ListItemProps } from './list_item/list_item';
export { ListSection } from './list_section/list_section';
export type { ListSectionProps } from './list_section/list_section';

import type { ReactNode } from 'react';
import type { TagColor } from './components/detail/detail_metadata';

export interface ListItemData {
  id: string;
  title: string;
  subtitle?: string;
  icon?: ReactNode;
  accessories?: ListItemAccessoryData[];
  detail?: ListItemDetailData;
}

export interface ListItemAccessoryData {
  text?: string;
  icon?: ReactNode;
  tag?: {
    text: string;
    color?: TagColor;
  };
}

export interface ListItemDetailData {
  markdown: string;
  metadata?: ListItemMetadataEntry[];
}

export type ListItemMetadataEntry =
  | {
      type: 'label';
      title: string;
      text?: string;
    }
  | {
      type: 'link';
      title: string;
      text: string;
      target: string;
    }
  | {
      type: 'tag-list';
      title: string;
      tags: {
        text: string;
        color?: TagColor;
      }[];
    }
  | { type: 'separator' };

export interface SectionData {
  title: string;
  items: ListItemData[];
}

export interface GridItemData {
  id: string;
  title: string;
  subtitle?: string;
  icon?: ReactNode;
}

export interface ColorItemData extends GridItemData {
  color: string;
}
